#!/usr/bin/env node
// ───────────────────────────────────────────────────────────────
// MODULE: Continuity Freshness Validator
// ───────────────────────────────────────────────────────────────

import { execFileSync } from 'node:child_process';
import fs from 'node:fs';
import path from 'node:path';
import * as yaml from 'js-yaml';
import { isMainModule } from '../lib/esm-entry.js';
import {
  buildContinuityFingerprint,
  ZERO_CONTINUITY_FINGERPRINT,
} from '../../mcp_server/lib/validation/spec-doc-structure.js';

const CONTINUITY_STALENESS_THRESHOLD_MS = 10 * 60 * 1000;
const FRONTMATTER_RE = /^(?:\uFEFF)?(?:\s*<!--[\s\S]*?-->\s*)*---\s*\r?\n([\s\S]*?)\r?\n---(?:\s*\r?\n|$)/;
const COMPLETION_DOCS = [
  'spec.md',
  'plan.md',
  'tasks.md',
  'checklist.md',
  'decision-record.md',
  'implementation-summary.md',
  'handover.md',
] as const;

type ResultStatus = 'pass' | 'warn' | 'fail';

export interface ContinuityFreshnessResult {
  readonly rule: 'CONTINUITY_FRESHNESS';
  readonly status: ResultStatus;
  readonly code:
    | 'fresh'
    | 'fresh_completion'
    | 'stale'
    | 'content_stale'
    | 'dirty_tree'
    | 'clock_drift'
    | 'no_completion_claim'
    | 'missing_fingerprint'
    | 'zero_fingerprint'
    | 'implementation_summary_missing'
    | 'missing_frontmatter'
    | 'missing_graph_metadata'
    | 'missing_graph_timestamp'
    | 'invalid_graph_metadata'
    | 'invalid_timestamp'
    | 'invalid_frontmatter';
  readonly message: string;
  readonly details: string[];
  readonly continuityTimestamp?: string;
  readonly graphTimestamp?: string;
  readonly deltaMs?: number;
}

interface CliOptions {
  folder: string;
  json: boolean;
  strict: boolean;
}

interface ContinuityFields {
  timestamp: string | null;
  fingerprint: string | null;
  completionPct: number | null;
  status: string | null;
  parseError: string | null;
}

interface CompletionCandidate {
  basename: string;
  filePath: string;
  content: string;
  fingerprint: string | null;
  hasCompletionClaim: boolean;
  recomputedFingerprint: string;
}

function toErrorMessage(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}

function isTruthyEnv(value: string | undefined): boolean {
  return ['1', 'true', 'yes', 'on'].includes((value ?? '').toLowerCase().trim());
}

function isEnforceMode(): boolean {
  return isTruthyEnv(process.env.SPECKIT_COMPLETION_FRESHNESS_ENFORCE);
}

function extractFrontmatter(markdown: string): string | null {
  return markdown.match(FRONTMATTER_RE)?.[1] ?? null;
}

function readContinuityFields(markdown: string): ContinuityFields {
  const frontmatterBlock = extractFrontmatter(markdown);
  if (!frontmatterBlock) {
    return {
      timestamp: null,
      fingerprint: null,
      completionPct: null,
      status: null,
      parseError: null,
    };
  }

  try {
    const parsed = yaml.load(frontmatterBlock) as Record<string, unknown> | null;
    const memory = parsed?._memory as Record<string, unknown> | undefined;
    const continuity = memory?.continuity as Record<string, unknown> | undefined;
    const sessionDedup = continuity?.session_dedup as Record<string, unknown> | undefined;
    const completionPct = continuity?.completion_pct;
    const rawStatus = parsed?.status;
    const metadataStatus = extractMetadataTableStatus(markdown);

    return {
      timestamp: typeof continuity?.last_updated_at === 'string' ? continuity.last_updated_at : null,
      fingerprint: typeof sessionDedup?.fingerprint === 'string'
        ? sessionDedup.fingerprint
        : typeof memory?.fingerprint === 'string'
          ? memory.fingerprint
          : null,
      completionPct: typeof completionPct === 'number'
        ? completionPct
        : typeof completionPct === 'string'
          ? Number.parseFloat(completionPct)
          : null,
      status: typeof rawStatus === 'string' ? rawStatus : metadataStatus,
      parseError: null,
    };
  } catch (error: unknown) {
    return {
      timestamp: null,
      fingerprint: null,
      completionPct: null,
      status: null,
      parseError: toErrorMessage(error),
    };
  }
}

function extractMetadataTableStatus(markdown: string): string | null {
  const match = markdown.match(/^\|\s*\*\*Status\*\*\s*\|\s*([^|]+?)\s*\|\s*$/im);
  return match?.[1]?.trim() || null;
}

function readContinuityTimestamp(markdown: string): {
  timestamp: string | null;
  parseError: string | null;
} {
  const fields = readContinuityFields(markdown);
  return { timestamp: fields.timestamp, parseError: fields.parseError };
}

function parseTimestamp(value: string): number | null {
  const parsed = Date.parse(value);
  return Number.isNaN(parsed) ? null : parsed;
}

function readGraphMetadataTimestamp(graphMetadataPath: string): {
  timestamp?: string;
  error?: string;
} {
  try {
    const parsed = JSON.parse(fs.readFileSync(graphMetadataPath, 'utf-8')) as {
      derived?: { last_save_at?: unknown };
    };
    return typeof parsed?.derived?.last_save_at === 'string'
      ? { timestamp: parsed.derived.last_save_at }
      : {};
  } catch (error: unknown) {
    return { error: toErrorMessage(error) };
  }
}

function buildPass(
  code: ContinuityFreshnessResult['code'],
  message: string,
  details: string[] = [],
  extra: Partial<ContinuityFreshnessResult> = {},
): ContinuityFreshnessResult {
  return {
    rule: 'CONTINUITY_FRESHNESS',
    status: 'pass',
    code,
    message,
    details,
    ...extra,
  };
}

function buildWarn(
  code: ContinuityFreshnessResult['code'],
  message: string,
  details: string[] = [],
  extra: Partial<ContinuityFreshnessResult> = {},
): ContinuityFreshnessResult {
  return {
    rule: 'CONTINUITY_FRESHNESS',
    status: 'warn',
    code,
    message,
    details,
    ...extra,
  };
}

function buildFail(
  code: ContinuityFreshnessResult['code'],
  message: string,
  details: string[] = [],
): ContinuityFreshnessResult {
  return {
    rule: 'CONTINUITY_FRESHNESS',
    status: 'fail',
    code,
    message,
    details,
  };
}

function isCompletionStatus(status: string | null): boolean {
  return /\b(?:complete|completed|done|shipped|implemented)\b/i.test(status ?? '');
}

function hasChecklistEvidenceClaim(basename: string, content: string): boolean {
  return basename === 'checklist.md'
    && /^\s*-\s+\[[xX]\].*(?:\[EVIDENCE:|\|\s*Evidence:|[✓✔☑✅]|\((?:verified|tested|confirmed)\)|\[DEFERRED:)/im.test(content);
}

function hasCompletionClaim(basename: string, content: string, fields: ContinuityFields): boolean {
  return fields.completionPct === 100
    || isCompletionStatus(fields.status)
    || hasChecklistEvidenceClaim(basename, content);
}

function collectCompletionCandidates(specFolderPath: string): CompletionCandidate[] {
  const candidates: CompletionCandidate[] = [];
  for (const basename of COMPLETION_DOCS) {
    const filePath = path.join(specFolderPath, basename);
    if (!fs.existsSync(filePath)) {
      continue;
    }
    const content = fs.readFileSync(filePath, 'utf-8');
    const fields = readContinuityFields(content);
    candidates.push({
      basename,
      filePath,
      content,
      fingerprint: fields.fingerprint,
      hasCompletionClaim: hasCompletionClaim(basename, content, fields),
      recomputedFingerprint: buildContinuityFingerprint(content),
    });
  }
  return candidates;
}

function findGitRoot(folderPath: string): string | null {
  try {
    return execFileSync('git', ['-C', folderPath, 'rev-parse', '--show-toplevel'], {
      encoding: 'utf-8',
      stdio: ['ignore', 'pipe', 'ignore'],
    }).trim();
  } catch {
    return null;
  }
}

function listPacketDirtyPaths(specFolderPath: string): string[] {
  const gitRoot = findGitRoot(specFolderPath);
  if (!gitRoot) {
    return [];
  }

  const relativeFolder = path.relative(gitRoot, specFolderPath).replace(/\\/g, '/');
  try {
    const output = execFileSync('git', ['-C', gitRoot, 'status', '--porcelain', '--', relativeFolder], {
      encoding: 'utf-8',
      stdio: ['ignore', 'pipe', 'ignore'],
    });
    return output
      .split('\n')
      .map((line) => line.trimEnd())
      .filter(Boolean)
      .map((line) => line.slice(3).trim())
      .filter(Boolean);
  } catch {
    return [];
  }
}

function evaluateCompletionFreshness(specFolderPath: string): ContinuityFreshnessResult | null {
  const completionClaims = collectCompletionCandidates(specFolderPath)
    .filter((candidate) => candidate.hasCompletionClaim);

  if (completionClaims.length === 0) {
    return buildPass(
      'no_completion_claim',
      'Continuity freshness skipped: no completion claim found',
    );
  }

  const candidatesWithFingerprint = completionClaims
    .filter((candidate) => candidate.fingerprint && /^sha256:[a-f0-9]{64}$/.test(candidate.fingerprint));

  if (candidatesWithFingerprint.length === 0) {
    return buildPass(
      'missing_fingerprint',
      'Continuity freshness skipped: completion claim has no stored session_dedup fingerprint',
    );
  }

  const usableCandidates = candidatesWithFingerprint
    .filter((candidate) => candidate.fingerprint !== ZERO_CONTINUITY_FINGERPRINT);

  if (usableCandidates.length === 0) {
    return buildPass(
      'zero_fingerprint',
      'Continuity freshness skipped: completion claim has only the zero fingerprint placeholder',
    );
  }

  const staleCandidates = usableCandidates
    .filter((candidate) => candidate.fingerprint !== candidate.recomputedFingerprint);
  const dirtyPaths = listPacketDirtyPaths(specFolderPath);

  if (staleCandidates.length > 0 || dirtyPaths.length > 0) {
    const details = [
      ...staleCandidates.map((candidate) => `${candidate.basename}: stored=${candidate.fingerprint} recomputed=${candidate.recomputedFingerprint}`),
      ...dirtyPaths.slice(0, 10).map((dirtyPath) => `dirty=${dirtyPath}`),
      'How to Fix: rerun verification, refresh session_dedup.fingerprint, and ensure packet paths are clean.',
      'fix: rerun the completion workflow after updating the packet continuity fingerprint.',
    ];
    const code = staleCandidates.length > 0 ? 'content_stale' : 'dirty_tree';
    const message = staleCandidates.length > 0
      ? 'Completion freshness is stale: stored continuity fingerprint does not match current content'
      : 'Completion freshness is stale: packet paths have uncommitted changes';

    return isEnforceMode()
      ? buildFail(code, message, details)
      : buildWarn(code, message, details);
  }

  return buildPass(
    'fresh_completion',
    'Completion freshness passed: completion claim fingerprint matches current content and packet paths are clean',
    usableCandidates.map((candidate) => `${candidate.basename}: recomputed=${candidate.recomputedFingerprint}`),
  );
}

#!/usr/bin/env node
/**
 * Ephemeral-pointer audit — enforces sk-code §4 "No Ephemeral-Artifact Pointers".
 *
 * Scans source files and flags CODE COMMENTS that embed pointers to ephemeral
 * artifacts (spec folders/numbers, task/checklist/requirement ids, review-finding
 * ids, ADR ids, ticket ids). The durable WHY of a comment is fine; only the
 * perishable traceability id is forbidden, because it rots once the spec is
 * archived or the review closes.
 *
 * What it does NOT flag (by design):
 *   - String/code content (only comment regions are inspected).
 *   - Durable/structural numbers: HTTP status codes, embedding dims, token tiers,
 *     rolling-window sizes, schema-version tags ("V16:").
 *   - JSDoc @example / parser-format illustrations that show input SHAPE
 *     (e.g. "019-system-hardening", "specs/001-demo", a quoted "NNN-name").
 *   - Runtime path constants the code actually reads (DEFAULT_ROOT-style lines).
 *
 * Standalone, dependency-free (Node ESM, stdlib only). Exit nonzero on any hit
 * so CI / pre-commit / sk-code verification can gate on it.
 *
 * Authoritative rule source:
 *   .opencode/skills/sk-code/references/universal/code_style_guide.md §4
 *
 * Usage:
 *   node ephemeral-pointer-audit.mjs <path> [<path> ...] [--json]
 *   node ephemeral-pointer-audit.mjs .opencode/skills .opencode/bin
 *   node ephemeral-pointer-audit.mjs <path> --json
 *
 * Exit codes: 0 = clean, 1 = violations found, 2 = bad invocation.
 */

import fs from "node:fs";
import path from "node:path";

// ---------------------------------------------------------------------------
// File selection
// ---------------------------------------------------------------------------

// Extensions whose comment syntax we understand.
const SCANNED_EXTENSIONS = new Set([".ts", ".tsx", ".js", ".jsx", ".mjs", ".cjs", ".py"]);

// Directories never worth scanning (vendored / build output / VCS).
const SKIP_DIRS = new Set([
  "node_modules",
  ".git",
  "dist",
  "build",
  "coverage",
  ".venv",
  "__pycache__",
  ".pytest_cache",
]);

// Extensionless files (e.g. .opencode/bin/spec-kit-mcp) are scanned when their
// shebang marks them as Node or Python — those use //, /* */, or # comments.
const SHEBANG_NODE = /^#!.*\b(node|deno|bun)\b/;
const SHEBANG_PY = /^#!.*\bpython[0-9.]*\b/;

// ---------------------------------------------------------------------------
// Forbidden ephemeral-id patterns (matched ONLY inside comment text)
// ---------------------------------------------------------------------------
//
// Each entry documents WHAT it catches so the allow-list reasoning stays legible.
// `name` is reported with the finding; `re` runs against a single comment's text.
//
// PRECISION OVER RECALL: each pattern is deliberately narrowed to the SHAPE of a
// real ephemeral tracking id and explicitly avoids durable look-alikes the live
// tree is full of — HTTP-code pairs (401/403), source line ranges (280-316),
// token-budget ranges (250-400), ratios (100/100), and externally-versioned
// standards (SHA-256, UTF-16, CWE-502, RFC-7231). Those carve-outs live both
// here (in the regex itself) and in the ALLOW table below.
const FORBIDDEN = [
  {
    name: "spec-folder-ref",
    // "Spec 031", "Phase 005", "Packet 117", "Iteration 12" — an explicit
    // tracking-artifact WORD immediately followed by a number. The leading word
    // is what makes this unambiguous (a bare number is never flagged here).
    re: /\b(?:spec|phase|packet|iteration|sprint)\s+0*\d{1,4}\b/i,
  },
  {
    name: "spec-pair-ref",
    // A spec / sub-phase pair: "031/005", "029/001", "005-001", "026/007/013".
    // CRITICAL precision constraint: at least ONE side must be a 3-digit
    // ZERO-PADDED number (leading 0), which is the spec-folder numbering
    // convention. This is what separates a real "029/003" from HTTP "401/403",
    // a line range "280-316", or a ratio "100/100" — none of which are
    // zero-padded. Optional third segment catches "026/007/013".
    re: /\b(?:0\d{2}[\/-]\d{3}|\d{3}[\/-]0\d{2})(?:[\/-]\d{3})?\b/,
  },
  {
    name: "spec-slug",
    // "031-embedding-stack-hardening" — 3-digit prefix + a kebab word slug.
    // Format-illustration shapes ("019-system-hardening" in an @example,
    // "specs/001-demo") are suppressed by the ALLOW table, not here.
    re: /\b\d{3}-[a-z][a-z0-9]*(?:-[a-z0-9]+)+\b/,
  },
  {
    name: "task-id",
    // Task ids: "T043", "T-123", "T73". Requires the token to be a STANDALONE
    // T+digits word (>=2 digits) and NOT immediately preceded by a letter, so
    // it never fires inside identifiers. Two-digit floor avoids loop vars (T1).
    re: /\bT-?\d{2,}\b/,
  },
  {
    name: "checklist-id",
    // "CHK-160", "CHK069" — checklist item ids.
    re: /\bCHK-?\d{2,}\b/i,
  },
  {
    name: "requirement-id",
    // "REQ-005", "REQ007" — requirement ids.
    re: /\bREQ-?\d{2,}\b/i,
  },
  {
    name: "adr-id",
    // "ADR-004", "ADR014" — architecture-decision-record ids.
    re: /\bADR-?\d{1,}\b/i,
  },
  {
    name: "review-finding-id",
    // Deep-review / agent finding tags: "DR-008", "WS-1", "OR-R-01", "F-001-005",
    // "P0-3", "P1-09", "P2-14", "DEC-12". Uppercase finding-prefix + dash +
    // digits, with optional extra dash-segments ("F-001-005", "A6-P2-2" tail).
    // The prefix set is an allow-list of KNOWN review schemes, NOT a generic
    // [A-Z]+ catch-all — that is what stops it eating SHA-256 / UTF-16 / CWE-22.
    re: /\b(?:DR|WS|OR(?:-R)?|F|P[012]|DEC|FND)-\d{1,}(?:-\d{1,})*\b/,
  },
  {
    name: "github-issue-ref",
    // "#456", "(#456)", "Fix #16", "Safeguard #10" — issue/PR references.
    // Standalone #-number token only (preceded by start / whitespace / bracket).
    re: /(?:^|[\s(\[])#\d{2,}\b/,
  },
];

// NOTE intentionally NOT a forbidden rule: a generic "ticket-id" /[A-Z]{3,}-\d/
// pattern. It is irresistibly drawn to durable standards the style guide §4
// EXPLICITLY allows — SHA-256, UTF-8/16, CWE-502, RFC numbers — and to the
// project's own non-ephemeral constants. A real external tracker key (JIRA-123,
// CU-8abc) is better caught by an opt-in project-specific prefix list than by a
// broad shape that produces a flood of false positives. See notes/wiring.

// ---------------------------------------------------------------------------
// Allowed exclusions — when ANY of these matches a comment, the listed
// forbidden rule(s) are suppressed for that comment. These encode the
// "durable / structural" carve-outs from the style guide §4.
// ---------------------------------------------------------------------------
const ALLOW = {
  // Format-illustration / example / JSDoc-shape context: suppress the spec-shaped
  // rules. These show input SHAPE, not a live traceability pointer.
  //   * @example specs/001-demo/spec.md
  //   format: "019-system-hardening" or "NNN-name"
  //   // e.g. specs/001-demo   |   // Parses folder paths like "...140-hybrid-rag/006-sprint-5"
  exampleContext:
    /@example\b|@param\b|@returns?\b|\be\.?g\.?\b|\bi\.?e\.?\b|\bformat\s*[:=]|\bNNN\b|\bpattern\s*[:=]|\bspecs?\/|\bsuch as\b|\bfolder paths? like\b|\blike\s+"|->/i,

  // Schema-version tags ("V16:", "V3:") are durable — never a spec ref.
  schemaTag: /\bV\d{1,}\s*:/,

  // Rolling-window descriptors ("200-decision window") are durable config.
  rollingWindow: /\b\d{1,4}-decision\b/i,

  // Runtime path constant lines (DEFAULT_ROOT = ".opencode/specs/..."). The path
  // is structural — the resolver reads it. Suppress spec-shaped rules on such lines.
  runtimePath: /\bDEFAULT_ROOT\b|\.opencode\/specs\b/,

  // Externally-versioned standards explicitly allowed by §4 ("a stable external
  // standard ... does not get archived with a sprint"). These collide in shape
  // with task/finding ids, so suppress those on any comment naming a standard.
  // SHA-256, UTF-8/16, CWE-79/400/502, RFC-7231, ISO-8601, base64, UTF8 BOM, etc.
  externalStandard: /\b(?:SHA|MD)-?\d{2,}\b|\bUTF-?\d{1,2}\b|\bUTF8\b|\bCWE-\d{1,}\b|\bRFC-?\d{2,}\b|\bISO-?\d{3,}\b|\bECMA-?\d{2,}\b/i,

  // Source-location references the running code does not chase as a tracking
  // artifact: "lines 280-316", "at lines 776-791", "(protocol.js:280-316)".
  // A bare numeric range next to "line(s)" or after a "file.ext:" is structural.
  // This suppresses spec-pair-ref ONLY (the rule whose shape a range can mimic).
  sourceLineRange: /\blines?\b|\.(?:ts|tsx|js|mjs|cjs|jsx|py):\d/i,

  // HTTP status pairs / token-budget ranges / score ratios. "401/403", "250-400",
  // "100/100", "404, retry on 500". Numbers here are durable values, not spec ids.
  // Recognized when the comment also names HTTP/status/token/budget/error context
  // OR when the pair is plainly non-zero-padded (already excluded by the rule's
  // own zero-pad constraint, but this catches narration like "map 401/403").
  numericValueContext:
    /\b(?:HTTP|status|code|token|budget|tier|ms|ratio|score|retry|error|backoff|dims?|dimensions?)\b/i,

  // Internal enumerated safeguards ("Safeguard #10") are durable design labels —
  // learned-feedback.ts documents a numbered "10 Safeguards" list — not GitHub issues.
  safeguardEnum: /\bsafeguards?\s+#?\d/i,
};

// Map each allow-context to the forbidden rule names it is permitted to suppress.
// Allow-contexts are deliberately narrow so a real id elsewhere on the line still
// fires (e.g. an @example line that ALSO drops a "DR-008" still reports DR-008,
// because exampleContext does not suppress review-finding-id).
const ALLOW_SUPPRESSES = {
  exampleContext: new Set(["spec-slug", "spec-pair-ref", "spec-folder-ref", "github-issue-ref"]),
  schemaTag: new Set([]), // schema tags don't look like any forbidden id; informational
  rollingWindow: new Set(["spec-pair-ref"]),
  runtimePath: new Set(["spec-slug", "spec-pair-ref", "spec-folder-ref"]),
  externalStandard: new Set(["task-id", "checklist-id", "requirement-id", "adr-id", "review-finding-id"]),
  sourceLineRange: new Set(["spec-pair-ref"]),
  numericValueContext: new Set(["spec-pair-ref"]),
  safeguardEnum: new Set(["github-issue-ref"]),
};

// ---------------------------------------------------------------------------
// Comment extraction
// ---------------------------------------------------------------------------
//
// Returns an array of { line, text } for each comment region. Line numbers are
// 1-based and point at the physical line where the comment text sits. String
// and code content is excluded so we never flag `const slug = "031-foo"`.

function extractComments(source, isPython) {
  if (isPython) return extractPyComments(source);
  return extractJsComments(source);
}

// Python: only `#` line comments. A `#` inside a string literal is ignored via a
// lightweight string-state scan (handles ' " and triple-quoted blocks).
function extractPyComments(source) {
  const out = [];
  const lines = source.split("\n");
  let inTriple = null; // null | "'''" | '"""'
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (inTriple) {
      const end = line.indexOf(inTriple);
      if (end !== -1) inTriple = null;
      continue; // inside a docstring/string block — no comment scanning
    }
    const res = scanPyLineForComment(line);
    if (res.tripleOpen) inTriple = res.tripleOpen;
    if (res.commentText !== null) out.push({ line: i + 1, text: res.commentText });
  }
  return out;
}

function scanPyLineForComment(line) {
  let inStr = null; // null | "'" | '"'
  for (let j = 0; j < line.length; j++) {
    const c = line[j];
    const triple = line.slice(j, j + 3);
    if (!inStr && (triple === "'''" || triple === '"""')) {
      // A triple-quote that doesn't close on the same line opens a block.
      const rest = line.indexOf(triple, j + 3);
      if (rest === -1) return { commentText: null, tripleOpen: triple };
      j = rest + 2; // skip the closing triple
      continue;
    }
    if (inStr) {
      if (c === "\\") j++; // skip escaped char
      else if (c === inStr) inStr = null;
      continue;
    }
    if (c === "'" || c === '"') {
      inStr = c;
      continue;

